var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨?","JPN":"おじさん？","ENG":"Mister?","TWN":"大叔？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다들 살아있었구나! 다행이야!","JPN":"みんな生きてたんだ！　良かった！","ENG":"I'm happy to see you all alive! What a relief!","TWN":"大家都還活著啊？太好了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아아, 코핀 컴퍼니의 아가씨로군.","JPN":"ああ、コフィンカンパニーの嬢ちゃんか。","ENG":"Ah, you're the one from the Coffin Company.","TWN":"啊啊，原來是科芬公司的小姐啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그쪽도 무사해서 다행이야.","JPN":"そっちも無事でよかった。","ENG":"Good to see you, too.","TWN":"妳也沒事真是太好了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"강하선에서 튕겨나간 후에 어떻게 됐는지 몰라 걱정했는데......","JPN":"降下船からの離脱以降、行方が知れず心配だったんだが……","ENG":"I was worried, not knowing what happened to you after you bounced out of the drop ship.","TWN":"妳從降落艙飛出去之後，我還很擔心妳不知道會發生了什麼事呢……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러고 보니 그 소년은 어디에 있지? 같이 있는 거 아니었나?","JPN":"そういえば、あの少年はどこだ？　一緒だったんじゃ？","ENG":"Speaking of which, where's that boy that was with you? I thought you two would be together.","TWN":"話說回來，那個少年在哪？他沒有跟妳在一起嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 선배는......","JPN":"あ、先輩は……","ENG":"Ah, he's...","TWN":"啊，前輩他……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"주시윤 선배라면 우리도 못 봤어.","JPN":"アキヤマ先輩のことなら、私たちも行方がわからないんです。","ENG":"We haven't seen Shiyoon anywhere.","TWN":"周時雲前輩的話，我們也沒看到。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"평소처럼 어딘가에서 게으름이라도 피우고 있는 거 아닐까?","JPN":"いつもどおり、どこかで怠けてるんじゃないですかね？","ENG":"Maybe he's goofing around somewhere like he always does.","TWN":"會不會和平時一樣去哪裡偷懶了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"당신은......?!","JPN":"あなたは……！？","ENG":"You...","TWN":"妳……？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"서, 서윤!! 배신자가 어째서 여기에?!","JPN":"ア、アオイ・シズカ！！　裏切り者がどうしてここに！？","ENG":"S-Seo Yoon! What are you doing here, traitor?","TWN":"徐、徐芸！！妳這個叛徒怎麼會在這裡？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 다들 그렇게 흥분하지 않아도 돼.","JPN":"ま、待って！　みんな落ち着いてよ。","ENG":"W-wait! You don't have to be so upset anymore.","TWN":"等、等等！大家別這麼激動。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사정 이야기를 하자면 길지만, 어쨌든 서윤은 이제 적이 아니야.","JPN":"事情を話すと長くなるけど、とにかくシズカはもう敵じゃないんだよ。","ENG":"It's a long story, but she's no longer an enemy.","TWN":"雖然說來話長，但總之徐芸不再是敵人了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그게 무슨 말이죠?","JPN":"それはどういうことです？","ENG":"What do you mean?","TWN":"這是什麼意思？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런 짓을 겪고도 그냥 적이 아니라는 말 한마디로 납득할 수는 없습니다!","JPN":"あんなことがあったのに、今さら敵じゃないと言われて納得できるはずがありません！","ENG":"We can't just accept her as an ally just because you say so! We went through too much trouble!","TWN":"就算經歷了那種事情，單憑一句話怎麼可能讓人接受。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까...... 아마도 서윤이 배신한 것처럼 행동했던 건 모두 우리 회사 사장님의 명령이었던 것 같아......","JPN":"だから……シズカが裏切ったのは、すべて社長命令によるものだったみたい……","ENG":"Well... It seems her betrayal was actually a part of the plan our CEO had in mind.","TWN":"所以說……徐芸會做出背叛我們的行動，大概全是老闆的命令……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자세한 이야기는 나중에 돌아가서 사장님께 물어보라고.","JPN":"詳しいことは、いずれ帰ったら社長に聞いてみてよ。","ENG":"Boss will tell you all the details when we get back.","TWN":"具體的細節你們回去後去問老闆吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 자, 뭐 좋아요. 어쨌든 우리 편이라는 거잖아요?","JPN":"まあまあ、とりあえずわかりましたよ。いずれにしても、今は味方ってことですね？","ENG":"Now, now. She's on our side, and that's what matters.","TWN":"好了，好了。不管怎樣，她是我們這邊的對吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"강력한 아군이 늘었다는 건 좋은 거죠.","JPN":"強力な味方が増えたわけですし、いいじゃないですか。","ENG":"We now have one more ally, and a powerful one at that.","TWN":"有強大的夥伴加入我們就是好事。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위! 그렇게 얼렁뚱땅 넘길 일이 아닌......","JPN":"マエカワ警部補！　そんな適当に流せることでは……","ENG":"Lieutenant Kang! It's not something you can gloss over!","TWN":"姜素英警衛！這可不是能夠隨便敷衍過去的事情……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"들으셨죠, 경정님?","JPN":"今の聞こえましたよね、警視様？","ENG":"Hear that, Major?","TWN":"聽到了吧，警正？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"지금은 저쪽 전장이 더 급해 보이지 않아요?","JPN":"今は、あちらの戦場のほうを優先すべきだと思いません？","ENG":"Doesn't the fight over there seem more urgent than this?","TWN":"現在那邊的戰場好像更緊迫的樣子？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무래도 예상과는 다르게 상황이 쉽게 풀리진 않을 모양이네요.","JPN":"どうやら予想に反して、そう簡単には解決できないようですね。","ENG":"As it turns out, things don't seem to work out so easily.","TWN":"看來和預想的不一樣，這個狀況沒辦法輕易地就解決掉呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"기왕 여기까지 왔으니까 빨리 지원군과 합류하는 게 좋을 것 같아요.","JPN":"せっかくここまで来たんですから、早く援軍と合流したほうが良さそうです。","ENG":"Now that we made it this far, we'll need to join forces with the reinforcements as quickly as possible,","TWN":"但既然都來到這裡了，我們還是快點和援軍會合吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......다 이긴 판이 뒤집어지기 전에.","JPN":"……勝利を横取りされる前に。","ENG":"before everything takes a turn for the worse.","TWN":"……在他們被翻盤之前。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일!","JPN":"カイル！","ENG":"Kyle!","TWN":"凱爾！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다시 나타났습니다! 3시 방향!","JPN":"また出現しました！　3時方向！","ENG":"She's appeared again! At your 3!","TWN":"又出現了！三點鐘方向！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이래서야 좀비가 따로 없군...... 대체 얼마나 쓰러트려야 끝나는 거지?","JPN":"これじゃ、ゾンビ同然だな……いったいいつまで倒せばいいんだ？","ENG":"This is like fighting zombies... How many more times do we have to kill her?","TWN":"簡直像殭屍一樣……到底要倒下幾個才會結束啊？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실비아! 뭔가 뾰족한 방법 없어?","JPN":"シルビア！　何かいい案はないか？","ENG":"Sylvia! Any ideas?","TWN":"希爾維亞！妳有什麼好辦法嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이럴 때만 찾기는!","JPN":"こんな時に限って頼らないでよ！","ENG":"Oh, now you're asking me for ideas?","TWN":"你就只會在這種時候問我！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나라고 이런 상황에 무슨 방법이......","JPN":"いくら私でも、こんな状況じゃ手も足も……","ENG":"I have none! What did you expe—","TWN":"這種情況我能有什麼辦法……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああ！！","ENG":"Eeeek!","TWN":"呀啊啊！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"조금 물러나렴, 실비아. 여긴 내가 맡지.","JPN":"下がってろ、シルビア。ここは私が引き受けよう。","ENG":"Try to stand back a little bit, Sylvia. I'll take it from here.","TWN":"稍微後退一點，希爾維亞。這裡交給我。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아줌마......","JPN":"お、おばさん……","ENG":"M-Maria?","TWN":"大、大嬸……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"적을...... 격멸...... 한다......","JPN":"敵を……撃滅……する……","ENG":"Enemies shall be... annihil... ated...","TWN":"殲滅……敵人……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크, 지금까지 몇 번쯤 쓰러트렸지?","JPN":"ジェイク、これまで何回くらい倒したんだ？","ENG":"Jake, did you count the kills?","TWN":"傑克，到目前為止，我們擊敗她幾次了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아마도...... 일곱 번째인 것 같습니다, 중장님.","JPN":"おそらく……7回目だと思います、中将。","ENG":"This is probably the seventh, Lieutenant General.","TWN":"大概有……七次了，中將大人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see...","TWN":"是喔。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저 리플레이서 나이트라는 친구...... 확실히 재생될 때마다 힘은 점점 더 강해지는 것 같지만, 어쩐지 정신은 계속 퇴행하는 것 같아 보이지 않나?","JPN":"あのリプレイサー・ナイトとかいう者、再生するたびに力は進化しても、\\nどこか精神は退行し続けているように見えないか？","ENG":"That Replacer Knight... She grows stronger every time she's regenerated, but doesn't her mind seem to be gradually fading away?","TWN":"這位叫作克隆．騎士的朋友……每次再生的時候，力量確實都變得越來越強大，但總覺得她的精神在逐漸退化，不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 확실히...... 그런 것 같군요.","JPN":"そう言われてみれば、たしかに……そのようです。","ENG":"Come to think of it, I guess you're right.","TWN":"這麼一說……好像確實是這樣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"재생체라고 해도 완전히 동일한 개체를 만들어내지는 못하는 것 같군.","JPN":"再生体とはいっても、完全に同じ個体を創り出すことはできないみたいだな。","ENG":"Regeneration doesn't seem to produce an exactly identical copy of the original.","TWN":"即使是再生體，也無法創造出完全一樣的個體。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하긴 점점 더 강해진다는 것 자체가 원본과 차이가 있다는 뜻이겠지.","JPN":"まあ、ますます強くなるということ自体、オリジナルとは開きがあるってことだろうからな。","ENG":"Well, the fact that the next one is stronger than the previous one is already an indication.","TWN":"越變越強的這件事本身，就代表她和原型有所差異。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일! 지금부터 리플레이서 나이트는 네가 단독으로 상대한다.","JPN":"カイル！　これからリプレイサー・ナイトは、君が単独で相手するんだ。","ENG":"Kyle! You're going to fight the Replacer Knight by yourself from now on.","TWN":"凱爾！從現在開始，由你自己一個人對付克隆·騎士。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네? 며, 명령이라면 따르겠지만 제 힘으로는......","JPN":"はい？　め、命令でしたら従いますが、僕の力では……","ENG":"Excuse me? I-I'll do it if it's an order, but with my strength...","TWN":"咦？如果這是命令的話，我會服從，但就憑我一個人的力量……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"쓰러트리려고 노력할 필요는 없다.","JPN":"倒そうとする必要はない。","ENG":"You won't have to defeat it.","TWN":"不用努力去打敗她。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나이트는 지금 정상적인 사고를 할 수 있는 상태가 아니야.","JPN":"ナイトは今、正常な思考ができるような状態ではないんだ。","ENG":"Knight is in no state to think reasonably.","TWN":"克隆．騎士現在不能正常思考。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그저 파상공세를 취하면서 시간만 끄는 것으로 족하다.","JPN":"だから、波状攻撃をしながら、時間稼ぎをしてくれるだけで十分だ。","ENG":"Just keep launching attacks and stall for time.","TWN":"只需要不斷發動攻勢，拖延時間就可以了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 사이에 제이크가 제이나...... 아니, 리플레이서 퀸을 친다.","JPN":"その間にジェイクがジェイナ、いや、リプレイサー・クイーンを撃退する。","ENG":"And meanwhile, Jake, you go for Jaina... I mean, Replacer Queen.","TWN":"與此同時，傑克就攻擊婕娜……不，是克隆．女皇。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"원래의 나이트였다면 이런 우회공격은 통하지 않았겠지만, 지금의 힘만 센 멍청이는 다양한 전술적인 움직임에 대응하지 못할 거다.","JPN":"本来のナイトならば、こんな攻撃は通じなかっただろうが、今の奴はまともな思考ができない。\\n様々な戦術に対応できないはずだ。","ENG":"This double threat tactics wouldn't be viable if Knight was in her normal condition, but being the muscle-packed fool she is, she won't be able to respond to a concurrent series of attacks.","TWN":"是以前的克隆．騎士的話，這種迂迴進攻不會管用，但是現在她只是徒有力氣而已，沒辦法應對這種多樣的戰術性行動。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"과연...... 그렇군요. 이건 먹힐 것 같은데요?","JPN":"なるほど……そういうことですね、これはイケるんじゃないですかね？","ENG":"That's... actually an amazing plan. It might just work!","TWN":"果然……是這樣。這招好像管用？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"역시 우리 중장님, 역전의 노익장은 여전하시군요.","JPN":"さすが中将、歴戦のベテランは格が違いますね。","ENG":"You're smart as a whip even in your advanced age, Lieutenant General.","TWN":"不愧是我們的中將大人，還是老當益壯啊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나이 들었다는 이야기를 칭찬이랍시고 하다니, 아부하는 법은 아직 멀었군. 제이크.","JPN":"年を取ったという話に喜ぶもんか。媚び方はまだまだだな、ジェイク。","ENG":"You don't compliment a person by telling them they're old. Work on your flattering, Jake.","TWN":"你竟然把老當作讚美的話，看來你還得學學怎麼拍馬屁啊，傑克。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"빨리 달리기나 하도록!","JPN":"わかったなら、急ぎたまえ！","ENG":"Just start running.","TWN":"跑快點！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 알겠습니다!","JPN":"ハハ、了解しました！","ENG":"Hah hah, yes, ma'am.","TWN":"哈哈，知道了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"흠...... 벌써 재생체의 취약점을 눈치챘나?","JPN":"ふむ……再生体の弱点にもう気づいたか？","ENG":"Hmm... You've already spotted the weakness of a regenerated Replacer.","TWN":"嗯……已經發現再生體的弱點了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하긴 대정화전쟁의 영웅인 당신이라면 이 정도는 당연하다고 봐야겠지.","JPN":"まあ、大浄化戦争の英雄であるあなたなら、これくらいは当然か。","ENG":"Well, I expect no less from the hero of the Grand Purification War.","TWN":"既然妳是淨化之戰的英雄，這種程度也是理所當然的吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"확실히 정상적으로 재생체의 의식을 안정시키려면 중추신경의 뉴런 연결을 강화하기 위한 조정기간이 필요하긴 하지만......","JPN":"確かに再生体の意識を安定させるためには、\\n中枢神経のニューロン接続を強化するための調整期間が必要ではあるが……","ENG":"You're right. Stabilizing the consciousness of regenerated Replacers takes time, since their newly built neuron network needs to settle in their central nervous system.","TWN":"想要穩定再生體的意識，就必須要有強化中樞神經原連接的調整時間……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"야전상황에서는 이런 방법도 가능하거든.","JPN":"混戦状態ではこんなやり方も可能だ。","ENG":"But out in the field, I can just do this.","TWN":"然而在野戰的情況下，這種方法也是可能的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"크으윽.......","JPN":"くううっ！！","ENG":"Ugh!","TWN":"吼喔喔……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"적은...... 어디에 있지......?","JPN":"敵は……どこだ……？","ENG":"Enemies... Where are the enemies?","TWN":"敵人……在哪裡……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"죽인다...... 버러지들!!","JPN":"殺す……虫けらども！！","ENG":"I'll kill you, worms!","TWN":"去死吧……螻蟻們！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이건......?!","JPN":"これは……！？","ENG":"This is...","TWN":"這是……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"재료만 충분하다면 재생체를 하나만 만들라는 법은 없지.","JPN":"材料さえ十分にあれば、再生体を一体にする必要はない。","ENG":"With enough ingredients, I can build more than one of them.","TWN":"要是材料充足的話，就不會只創造一個再生體吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 인자를 재생체용 프로그레시브 인자로 전환하는 건 매우 비효율적인 공정이라 평소라면 쓸 수 없는 방법이지만......","JPN":"リプレイサーファクターを再生体向けのプログレッシブファクターに切り替えるのは、\\n非常に効率の悪いやり方だから普段なら使えない方法だが……","ENG":"Converting the Replacer Factors to the Regenerative Progressive Factors is a very inefficient process which we used to use, and now avoid at all costs,","TWN":"將克隆因子轉化成再生體用的可操控因子，是極為沒有效率的工程，平時是不會使用的……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"전 세계에 로스트 쉽이 깔린 지금은 침식 증후군 감염자들을 리플레이서 인자 생산공장으로 전환할 수 있으니까......","JPN":"世界中にロストシップが布陣している今なら、\\n侵食症候群の感染者を、リプレイサーファクター生産工場として使える……","ENG":"But now we have Lost Ships all over the world. We can turn any individual suffering from Corruption Syndrome into a manufacturing plant for Replacer Factors.","TWN":"但在世界各地都遍佈失落艦船的現在，就可以把侵蝕症候群的感染者們轉換成克隆因子生產工廠……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그동안 수급해둔 양이 꽤 되거든.","JPN":"これまで確保した数がかなりあるからな。","ENG":"And thanks to that, we've collected enough of it.","TWN":"這段時間收集的量也夠多了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그럼 그 생산공장으로 쓰인 사람들은 어떻게 되는 건데?","JPN":"何だって？　じゃ、その生産工場になった人々はどうなるの？","ENG":"What? What happens to them after they've served their purpose?","TWN":"什麼？你們把那些被當成生產工廠使用的人們怎麼了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"치료용으로 투입된 이터니움 정제와 신체대사 에너지가 모두 리플레이서 인자 재생산에 소모되니까......","JPN":"治療用に投入されるエタニウム精製や代謝エネルギーは\\nすべてリプレイサーファクターの再生産に消費される……","ENG":"Of course, all the refined Eternium injected for therapeutic purposes, along with every bit of their metabolic energy, will be consumed for Replacer Factor production, so...","TWN":"由於治療投入的永恆之金提煉和身體的代謝能量，都是克隆因子再生所需要的……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"아마도 쇠약해지다가...... 결국은 죽겠지.","JPN":"恐らく次第に衰弱していき……最後は死ぬだろうな。","ENG":"They'll grow weak, and die eventually.","TWN":"那些人們大概會逐漸衰弱……然後死去吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 무슨...... 악마 같은 짓을......","JPN":"そんな……悪魔みたいなことを……","ENG":"You... You demons...","TWN":"這是什麼……惡魔般的行徑……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"수단과 방법을 가리지 말고 적을 압도하라.","JPN":"手段を選ばず敵を圧倒せよ。","ENG":"Use all means necessary to take the upper hand.","TWN":"不擇手段的方法去壓倒敵人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"모두 당신이 내게 가르쳐 준 방식이지.","JPN":"すべてあなたが私に教えてくれたやり方だ。","ENG":"That's what you taught me.","TWN":"這是妳教我的方法啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그렇지 않나? 안토노프 사령관.","JPN":"そうではないか？　アントノフ司令官。","ENG":"Wasn't it, Commander Antonov.","TWN":"不是嗎？安東諾夫司令官。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"자, 내 차례는 끝났다. 어떻게 응수할 거지?","JPN":"さあ、私の番は終わった。あなたはどう出るのか？","ENG":"Now, I've made my move. How are you going to respond?","TWN":"好了，我的回合結束了。妳要怎麼回應呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실비아?!","JPN":"シルビア！？","ENG":"Sylvia?!","TWN":"希爾維亞？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어?","JPN":"うん？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"코, 코핀 컴퍼니 친구들? 어떻게 여기에......?","JPN":"コ、コフィンカンパニーのみんな？　どうしてここに……？","ENG":"The Coffin Company? How are you here?","TWN":"科、科芬公司的朋友們？你們為什麼會在這裡……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너희들 근무지 무단 이탈로 실종 상태라고 들었는데......","JPN":"みんなは作戦区域から離れて、失踪状態だって聞いたんだけど……","ENG":"I heard you went AWOL and have been missing ever since.","TWN":"我聽說你們擅自離開工作地點，而且失蹤了啊……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 이야기하자면 긴데...... 원래 우리가 여기에 먼저 와 있었거든?","JPN":"あ、話すと長くなるけど……元々は私たちのほうが先にここに着いてたんだよ。","ENG":"It's a long story, but we got here way before you did.","TWN":"啊，說來話長……但本來是我們先到這裡的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그게 무슨......","JPN":"え？　それはどういう……","ENG":"Huh? What do you mean?","TWN":"什麼？這怎麼可能……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"설마 이곳 좌표를 찾아내서 프리덤 스트라이크를 호출한 게 너희들이었어?","JPN":"まさかここの座標を見つけてフリーダムストライクを呼び出したのは、みんなだったの？","ENG":"Was it you that sent in the coordinates and called the Freedom Strike?","TWN":"該不會找到這裡的座標，呼叫自由之擊的是你們嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어...... 그것까진 난 잘 모르겠지만......","JPN":"うーん……そこまではわからないけど……","ENG":"Umm... That, I don't know much about, but...","TWN":"呃……這段過程我不是很清楚……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 말대로다. 다시 만나서 반갑군, 아가씨.","JPN":"そのとおりだ、再会できて嬉しいな、嬢ちゃん。","ENG":"What you said. It's good to see you again, young lady.","TWN":"說得沒錯。很高興又見面了，小姐。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"메이슨 용병 아저씨?","JPN":"傭兵のおじさん？","ENG":"Mr. Mason?","TWN":"梅森傭兵大叔？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"기억해 주니 고맙군.","JPN":"覚えてくれてたんだな。","ENG":"It's nice to know that you remember me.","TWN":"很高興妳還記得我。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우린 불멸체 코어가 발산하는 차원간섭파를 역추적해서 이곳을 찾아냈지.","JPN":"俺らは不滅体コアが発する次元干渉波を逆探知して、ここを見つけたんだ。","ENG":"We traced back the dimension interference waves being emitted from the Immortal System Core and ended up here.","TWN":"我們對不滅者核心發出的次元干涉波進行逆向追蹤後，才找到了這裡。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 후에 뉴 오하이오를 해킹해서 스텔스 필드를 해제하고 지원을 부른 거다.","JPN":"そして、ニューオハイオをハッキングしてステルスフィールドを解除した後、援軍を要請したんだ。","ENG":"Then we hacked into the New Ohio, disabled its stealth field, and called for backup.","TWN":"然後我們侵入了新俄亥俄的網路，解除了隱形場域，並呼叫了支援。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"물론 지원 요청은 정보기관의 연줄을 통해서 하긴 했지만.","JPN":"もちろん、支援要請は情報機関のコネを通じてだが。","ENG":"Of course the calling for backup part was done through someone I know from Intelligence.","TWN":"當然支援請求是透過情報機關叫來的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"머......","JPN":"あ……","ENG":"C-cool!","TWN":"帥……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"멋져!! 멋지다고!!","JPN":"すごい！！　すごすぎるよ！！","ENG":"That's so awesome!","TWN":"帥斃了！！太厲害了！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어떻게 그런 방법을 찾아낸 거지? 역시 두뇌파 용병 존 메이슨!","JPN":"どうやってそんなこと思いついたの？　さすが頭脳派傭兵のジョン・メイソン！","ENG":"How did you come up with such an amazing idea? You really live up to your nickname, \\"the Intelligent Mercenary!\\"","TWN":"到底是怎麼想到這種方法的？不愧是頭腦派傭兵約翰．梅森！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후후, 이번에도 또 메이슨 용병 사무소의 이름을 떨쳐 버린 건가......","JPN":"フフ、今回もまたメイソン傭兵事務所の名を轟かせてしまったのか……","ENG":"Hah hah. And yet again, I ended up furthering the reputation of Mason Mercenary Office without realizing...","TWN":"嘿嘿，這次梅森傭兵事務所又出名了呢……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 여기에 온 것도......?","JPN":"ってことは、ひょっとしてここに来たのも……？","ENG":"And you being here was...","TWN":"那麼你們來這裡是……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아아, 보아하니 일손이 딸리는 것 같아서 말이지.","JPN":"ああ、人手が足りないんじゃないかと思ってな。","ENG":"Ah, I thought you might run short of hands.","TWN":"啊啊，因為你們人手看起來不太夠的樣子。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"혹시 지원군이 필요한가?","JPN":"援軍が必要だったりするか？","ENG":"Do you need help?","TWN":"需要援軍嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물론이지!","JPN":"もちろん！","ENG":"Of course we do!","TWN":"當然！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 저 사람들은......?","JPN":"カイル、あの人たちは……？","ENG":"Kyle, who are they?","TWN":"凱爾，那些人……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지난번 리플레이서와의 전투에서 합동작전을 펼쳤던 코핀 컴퍼니와 메이슨 용병 사무소의 전투 대원들입니다.","JPN":"この前のリプレイサーとの戦闘で、合同作戦を展開した\\nコフィンカンパニーとメイソン傭兵事務所の方たちです。","ENG":"They're combat operatives from the Coffin Company and Mason Mercenary Office, the TASKFORCE teams we worked with in the last battle against the Replacers.","TWN":"那是上次在和克隆集團戰鬥時，和我們一起作戰的科芬公司和梅森傭兵事務所的戰鬥隊員。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"둘 다 그다지 알려지진 않았지만, 같이 싸워본 결과 꽤...... 믿을 만한 사람들입니다.","JPN":"いずれもそこまで知られてはいませんが、一緒に戦ってみたところ、\\nかなり……信頼のおけるメンバーだと思います。","ENG":"They're not widely known yet, but from my experience... I'd say that they're quite reliable.","TWN":"雖然兩者都不是很有名，但一起戰鬥過之後，是非常……值得信賴的人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 네가 그 정도로 평가하는 걸 보니 정말 대단한 친구들인 것 같군.","JPN":"カイル、君がそこまで評価するなんて、かなりの凄腕なんだろうな。","ENG":"You rarely speak so highly of others, Kyle. They must be capable people.","TWN":"凱爾，你都這樣評價了，看來是真的很厲害的人啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"들었지? 리플레이서 퀸.","JPN":"聞こえたか？　リプレイサー・クイーン。","ENG":"Hear that, Replacer Queen?","TWN":"聽到了吧？克隆．女皇。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이쪽도 예비대가 생긴 것 같군. 그럼 이제 다시 동점인 건가?","JPN":"こちらにも予備隊ができたみたいだ。これで、振り出しに戻った感じか？","ENG":"Looks like our reinforcements have arrived. Then are we back to even?","TWN":"我們這邊也有支援部隊了。現在又是平局了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......쓸데없는 짓을.","JPN":"……無駄なことを。","ENG":"It won't make any difference.","TWN":"……沒用的掙扎。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"굳이 시간 낭비를 하고 싶다면 말리진 않겠지만......","JPN":"どうしても時間を無駄にしたいなら、止めはしないが……","ENG":"Waste time all you want,","TWN":"你們非要浪費時間，我是不會阻攔的……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그래 봐야 제물이 늘어난 것뿐이다.","JPN":"そんなことをしたところで、生贄が増えるだけだ。","ENG":"but what you did was only add to the number of sacrifices.","TWN":"這樣只是多了幾個祭品而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"결과는 달라지지 않아.","JPN":"結果は変わらないからな。","ENG":"The result will be the same.","TWN":"結果不會改變。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제물......?","JPN":"生贄……？","ENG":"Sacrifices?","TWN":"祭品……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그건 싸워봐야 아는 일일 것 같은데?","JPN":"それはやってみないとわからないのではないか？","ENG":"We can't be sure until we start, can we?","TWN":"那是戰鬥之後才知道的吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"서윤.","JPN":"シズカ。","ENG":"Seo Yoon.","TWN":"徐芸。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"한 번 달아날 기회를 줬는데도 다시 여기로 돌아오다니 너답지 않군.","JPN":"一度逃げるチャンスを与えたのに、ここに戻るなんてお前らしくないな。","ENG":"It's not like you to crawl back here when we gave you a chance to flee.","TWN":"我給了妳機會逃跑，結果妳竟然又回來了，這真不像妳。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"평소에는 나와 눈도 잘 못 마주쳤던 것 같은데.","JPN":"いつもは私と目を合わせることすらできなかったのに。","ENG":"You weren't able to look at me eye to eye before.","TWN":"平時妳都沒辦法直視我呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"주변에 동료들이 많이 모이니 이제 어깨에 힘이 좀 들어가기라도 했나?","JPN":"周りに味方が多いからって、強がってるのか？","ENG":"Do you feel confident now that you have all your colleagues by your side?","TWN":"現在身旁的同伴一多，妳就稍微敢囂張了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하하.","JPN":"あはは。","ENG":"Hah hah.","TWN":"哈哈。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"수단과 방법을 가리지 말고 소인배처럼 싸워라.","JPN":"手段を選ばずに、弱者のような戦い方を徹底しろ。","ENG":"Use all means necessary to fight like a coward.","TWN":"像小人一樣，用不擇手段的方法去戰鬥。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신이 가르쳐 준 거잖아?","JPN":"あなたが教えてくれたことでしょ？","ENG":"Wasn't that what you taught me?","TWN":"這不是妳教我的嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......그런 걸 가르치고 다녔나? 내가 가르친 것과는 좀 미묘하게 다른데.","JPN":"……そんなことを教えたか？　私が教えたのとは微妙に違うな。","ENG":"Was that what you went around telling your subordinates? That doesn't sound the same as what I taught you, does it?","TWN":"……我有教妳這個嗎？這和我教的好像有點不一樣吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 좋다. 부 사령관님의 계획과는 다르지만, 네가 굳이 악수를 두겠다면 나로서도 어쩔 수 없는 일이지.","JPN":"まあ、良い。副司令官様の計画とは異なるが、お前がそうくるなら、私としても致し方ない。","ENG":"Very well. It's a little different than what Deputy Commander had in mind, but if you're set on making a terrible decision, so be it.","TWN":"好吧。雖然和副司令官的計畫不一樣，但你們非要出狠招的話，那我也沒辦法。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"말이 길었군. 다들 덤벼라.","JPN":"話が長引いたな。みんな、かかってこい。","ENG":"Enough talking. Come at me.","TWN":"話說得夠多了。你們全部上來吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"시간은 짧고 목숨은 덧없는 것이니......","JPN":"時間は短く、命は儚いものだ……","ENG":"For time is short, and life is shorter...","TWN":"畢竟光陰短暫，生命又為飄渺之物……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RSYSTEM_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전투방출 중인 CRF 흡수 중.</color>","JPN":"<color=#ffd34c>戦闘放出中のCRFを吸収中。</color>","ENG":"<color=#ffd34c>Absorbing CRF currently being released for combat purposes.</color>","TWN":"<color=#ffd34c>正在吸收戰鬥排放的CRF。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L34_1","type":"dialog","speaker":"RSYSTEM_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리플레이서 인자 진화 임계치까지...... 87%.</color>","JPN":"<color=#ffd34c>リプレイサーファクターの進化臨界点まで……87％。</color>","ENG":"<color=#ffd34c>Replacer Factor evolution meter, currently at 87%.</color>","TWN":"<color=#ffd34c>克隆因子進化臨界值……達到87%。</color>"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};